class Table{constructor(n){this.n=n;this.rows=JSON.parse(localStorage.getItem(n)||'[]')}save(){localStorage.setItem(this.n,JSON.stringify(this.rows))}async count(){return this.rows.length}async toArray(){return [...this.rows]}orderBy(k){return {reverse:()=>({toArray:async()=>[...this.rows].sort((a,b)=>String(b[k]).localeCompare(String(a[k])))})}}async add(x){x.id=x.id||Date.now()+Math.floor(Math.random()*999);this.rows.push(x);this.save();return x.id}async bulkAdd(xs){for(const x of xs)await this.add(x)}async update(id,x){let r=this.rows.find(a=>a.id===id); if(r)Object.assign(r,x); this.save()}async delete(id){this.rows=this.rows.filter(a=>a.id!==id);this.save()}}
export class Dexie{version(){return {stores:(s)=>{for(const k of Object.keys(s))this[k]=new Table(k)}}} async transaction(_m,_a,_b,cb){return cb()}}
export default Dexie;
